// pdf-builder.mjs
// Builds Beoordeling and Verklaring PDFs using pdf-lib
// Returns Uint8Array buffers ready to attach to email

import { PDFDocument, rgb, StandardFonts, PageSizes } from 'pdf-lib';

// ── Brand colours ─────────────────────────────────────────────────────────
const C = {
  accent:  rgb(0/255, 138/255, 209/255),   // #008AD1
  accentD: rgb(0/255, 110/255, 168/255),   // #006ea8
  bg:      rgb(247/255, 248/255, 250/255), // #f7f8fa
  border:  rgb(228/255, 231/255, 237/255), // #e4e7ed
  text:    rgb(26/255,  29/255,  35/255),  // #1a1d23
  text2:   rgb(90/255,  96/255, 112/255),  // #5a6070
  text3:   rgb(154/255,160/255, 173/255),  // #9aa0ad
  white:   rgb(1, 1, 1),
  ok:      rgb(26/255, 127/255,  75/255),  // #1a7f4b
  okBg:    rgb(237/255, 250/255, 243/255),
  warn:    rgb(146/255, 98/255,  10/255),  // #92620a
  warnBg:  rgb(255/255, 251/255, 235/255),
  err:     rgb(192/255, 57/255,  43/255),  // #c0392b
  errBg:   rgb(254/255, 242/255, 242/255),
  accentBg:rgb(230/255, 243/255, 251/255), // #e6f3fb
};

const LOGO_B64   = '';
const HEADER_B64 = '';

// ── Helpers ────────────────────────────────────────────────────────────────
function b64ToUint8(b64) {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

function scoreInfo(score) {
  if (score === 'V')   return { label: 'Voldoende',   bg: C.okBg,   fg: C.ok   };
  if (score === 'O')   return { label: 'Onvoldoende', bg: C.errBg,  fg: C.err  };
  if (score === 'NvT') return { label: 'NvT',         bg: C.warnBg, fg: C.warn };
  return { label: '—', bg: C.bg, fg: C.text3 };
}

function wrapText(text, font, size, maxWidth) {
  const words = String(text).split(' ');
  const lines = [];
  let line = '';
  for (const word of words) {
    const test = line ? line + ' ' + word : word;
    if (font.widthOfTextAtSize(test, size) <= maxWidth) {
      line = test;
    } else {
      if (line) lines.push(line);
      line = word;
    }
  }
  if (line) lines.push(line);
  return lines;
}

// Draw a filled rectangle
function rect(page, x, y, w, h, color) {
  page.drawRectangle({ x, y, width: w, height: h, color });
}

// Draw text, returns nothing
function text(page, str, x, y, font, size, color) {
  if (!str) return;
  page.drawText(String(str), { x, y, font, size, color });
}

// Draw wrapped text, returns final y position
function textWrapped(page, str, x, y, font, size, color, maxWidth, lineHeight) {
  const lines = wrapText(str, font, size, maxWidth);
  for (const line of lines) {
    page.drawText(line, { x, y, font, size, color });
    y -= lineHeight;
  }
  return y;
}

// Draw horizontal line
function hline(page, x, y, w, color, thickness = 0.5) {
  page.drawLine({ start: {x, y}, end: {x: x+w, y}, thickness, color });
}

// ── BEOORDELING PDF ────────────────────────────────────────────────────────
export async function buildBeoordelingPdf(data) {
  const {
    datum_training, naam_opleider, email_opleider,
    naam_trainee, email_trainee, boot, functie,
    scores, toelichting, conclusie, toelichting_aanbeveling,
  } = data;

  const datumNl = datum_training
    ? datum_training.split('-').reverse().join('-')
    : '—';
  const vandaag = new Date().toLocaleDateString('nl-NL');

  const doc  = await PDFDocument.create();
  const page = doc.addPage(PageSizes.A4);
  const { width, height } = page.getSize();

  const bold   = await doc.embedFont(StandardFonts.HelveticaBold);
  const normal = await doc.embedFont(StandardFonts.Helvetica);

  const ML = 28;  // margin left
  const MR = 28;  // margin right
  const CW = width - ML - MR;  // content width

  // Logo
  const logoImg = await doc.embedJpg(b64ToUint8(LOGO_B64));
  let y = height;

  // ── Header banner ─────────────────────────────────────────────────────
  const BANNER_H = 72;
  rect(page, 0, height - BANNER_H, width, BANNER_H, C.accent);

  // Logo in banner
  page.drawImage(logoImg, { x: ML, y: height - BANNER_H + 16, width: 40, height: 40 });

  text(page, 'Beoordeling Vaartraining', ML + 52, height - 26, bold, 16, C.white);
  text(page, `Functie: ${functie}   ·   Boot: ${boot}`, ML + 52, height - 42, normal, 9, rgb(0.8,0.9,1));
  text(page, `Opgemaakt op ${vandaag} door ${naam_opleider}`, ML + 52, height - 54, normal, 8, rgb(0.7,0.82,0.93));

  y = height - BANNER_H - 18;

  // ── Section label ─────────────────────────────────────────────────────
  const sectionLabel = (label) => {
    text(page, label.toUpperCase(), ML, y, bold, 7.5, C.accent);
    y -= 12;
  };

  // ── Info table row ────────────────────────────────────────────────────
  const COL1 = CW * 0.38;
  const infoRow = (label, value, shade) => {
    if (shade) rect(page, ML, y - 4, CW, 18, C.bg);
    text(page, label, ML + 4, y + 3, normal, 9, C.text2);
    text(page, value || '—', ML + COL1 + 4, y + 3, bold, 10, C.text);
    hline(page, ML, y - 4, CW, C.border);
    y -= 18;
  };

  sectionLabel('Gegevens Trainingsvaart');
  infoRow('Datum training',  datumNl,        false);
  infoRow('Boot',            boot,           true);
  infoRow('Naam opleider',   naam_opleider,  false);
  infoRow('E-mail opleider', email_opleider, true);
  infoRow('Naam trainee',    naam_trainee,   false);
  infoRow('E-mail trainee',  email_trainee,  true);
  infoRow('Functie trainee', functie,        false);

  y -= 10;
  hline(page, ML, y, CW, C.border);
  y -= 16;

  // ── Criteria table ────────────────────────────────────────────────────
  sectionLabel(`Beoordeling ${functie}`);

  // Header row
  const SCORE_COL = 100;
  const CR_COL    = CW - SCORE_COL;
  rect(page, ML, y - 4, CW, 20, C.accent);
  text(page, 'Criterium',   ML + 6, y + 5, bold, 9, C.white);
  text(page, 'Beoordeling', ML + CR_COL + 14, y + 5, bold, 9, C.white);
  y -= 24;

  for (let i = 0; i < scores.length; i++) {
    const { label, score } = scores[i];
    const { label: slabel, bg, fg } = scoreInfo(score);
    const ROW_H = 20;

    if (i % 2 === 1) rect(page, ML, y - 4, CW, ROW_H, C.bg);

    // Wrap criterion label
    const crLines = wrapText(`${i+1}. ${label}`, normal, 9.5, CR_COL - 10);
    const actualH = Math.max(ROW_H, crLines.length * 13 + 8);
    if (crLines.length > 1) {
      if (i % 2 === 1) rect(page, ML, y - actualH + 16, CW, actualH, C.bg);
    }

    let cy = y + 2;
    for (const line of crLines) {
      text(page, line, ML + 6, cy, normal, 9.5, C.text);
      cy -= 13;
    }

    // Badge
    const BADGE_W = 76;
    const BADGE_X = ML + CR_COL + (SCORE_COL - BADGE_W) / 2;
    rect(page, BADGE_X, y - 2, BADGE_W, 14, bg);
    const bw = bold.widthOfTextAtSize(slabel, 8.5);
    text(page, slabel, BADGE_X + (BADGE_W - bw)/2, y + 1, bold, 8.5, fg);

    hline(page, ML, y - 4, CW, C.border);
    y -= actualH;
  }

  y -= 6;

  // Toelichting criteria
  if (toelichting) {
    rect(page, ML, y - 6, CW, 14, C.bg);
    page.drawRectangle({ x: ML, y: y - 6, width: CW, height: 14, borderColor: C.border, borderWidth: 0.5 });
    text(page, `Toelichting beoordeling ${functie}:`, ML + 6, y - 1, bold, 8.5, C.text2);
    y -= 18;
    y = textWrapped(page, toelichting, ML + 6, y + 2, normal, 9.5, C.text2, CW - 12, 13);
    y -= 6;
  }

  y -= 6;
  hline(page, ML, y, CW, C.border);
  y -= 16;

  // ── Aanbeveling ───────────────────────────────────────────────────────
  sectionLabel('Aanbeveling');

  // Conclusie box with left accent bar
  rect(page, ML, y - 6, 4, 26, C.accent);
  rect(page, ML + 4, y - 6, CW - 4, 26, C.accentBg);
  text(page, conclusie, ML + 14, y + 6, bold, 11, C.accent);
  y -= 36;

  if (toelichting_aanbeveling) {
    rect(page, ML, y, CW, 14, C.bg);
    page.drawRectangle({ x: ML, y: y, width: CW, height: 14, borderColor: C.border, borderWidth: 0.5 });
    text(page, 'Toelichting aanbeveling:', ML + 6, y + 4, bold, 8.5, C.text2);
    y -= 16;
    y = textWrapped(page, toelichting_aanbeveling, ML + 6, y + 2, normal, 9.5, C.text2, CW - 12, 13);
  }

  // ── Footer ────────────────────────────────────────────────────────────
  const FOOTER_H = 22;
  rect(page, 0, 0, width, FOOTER_H, C.bg);
  hline(page, 0, FOOTER_H, width, C.border);
  const ftxt = `de Fietsboot  ·  Beoordeling Vaartraining  ·  Gegenereerd op ${vandaag}`;
  const fw = normal.widthOfTextAtSize(ftxt, 8);
  text(page, ftxt, (width - fw)/2, 8, normal, 8, C.text3);

  return doc.save();
}


// ── VERKLARING PDF ─────────────────────────────────────────────────────────
export async function buildVerklaringPdf(data) {
  const { naam_trainee, naam_opleider, functie, boot } = data;
  const vandaag = new Date().toLocaleDateString('nl-NL');

  const doc  = await PDFDocument.create();
  const page = doc.addPage(PageSizes.A4);
  const { width, height } = page.getSize();

  const bold   = await doc.embedFont(StandardFonts.HelveticaBold);
  const normal = await doc.embedFont(StandardFonts.Helvetica);
  const italic = await doc.embedFont(StandardFonts.HelveticaOblique);

  const ML = 28;
  const MR = 28;
  const CW = width - ML - MR;

  // Header image (PNG)
  const headerImg = await doc.embedPng(b64ToUint8(HEADER_B64));
  const headerDims = headerImg.scaleToFit(CW, 60);
  page.drawImage(headerImg, { x: ML, y: height - headerDims.height - 14, ...headerDims });

  let y = height - headerDims.height - 30;

  text(page, 'Verklaring van Bekwaamheid', ML, y, bold, 18, C.accent);
  y -= 16;
  text(page, `Opgemaakt op ${vandaag}`, ML, y, normal, 9, C.text3);
  y -= 20;
  text(page, 'Hierbij verklaren wij,', ML, y, bold, 11, C.text2);
  y -= 20;

  const BOX_PADDING = 12;
  const BOX_INNER   = CW - BOX_PADDING * 2;

  const drawSection = (titleStr, paragraphs, naamStr) => {
    // Measure height needed
    let neededH = 20; // title
    for (const p of paragraphs) {
      const lines = wrapText(p, normal, 10, BOX_INNER);
      neededH += lines.length * 13 + 8;
    }
    neededH += 52; // signature area

    // Box background + border
    rect(page, ML, y - neededH, CW, neededH, C.bg);
    page.drawRectangle({
      x: ML, y: y - neededH, width: CW, height: neededH,
      borderColor: C.border, borderWidth: 0.5,
    });

    let cy = y - BOX_PADDING - 4;

    // Section title
    text(page, titleStr.toUpperCase(), ML + BOX_PADDING, cy, bold, 8, C.accent);
    cy -= 16;

    // Paragraphs
    for (const p of paragraphs) {
      cy = textWrapped(page, p, ML + BOX_PADDING, cy, normal, 10, C.text2, BOX_INNER, 13);
      cy -= 6;
    }

    cy -= 6;

    // Signature row: Naam left, Handtekening right
    const halfW = (BOX_INNER - 16) / 2;
    text(page, 'Naam:', ML + BOX_PADDING, cy, normal, 9, C.text2);
    text(page, 'Handtekening:', ML + BOX_PADDING + halfW + 16, cy, normal, 9, C.text2);
    cy -= 14;
    text(page, naamStr, ML + BOX_PADDING, cy, bold, 10.5, C.text);
    // Signature line
    hline(page, ML + BOX_PADDING + halfW + 16, cy - 2, halfW, C.text, 0.8);

    y -= neededH + 10;
  };

  drawSection('Kandidaat', [
    `Dat ik in staat ben gesteld om alle kennis en kunde tot mij te nemen die nodig wordt geacht om naar behoren te kunnen functioneren als ${functie} op ${boot}.`,
    `Van deze Verklaring maken onlosmakelijk deel uit de Vaarinstructies voor Fb1 en Fb2, zoals deze zijn gepubliceerd op de website "het Stuurhuis". Ik ben erop bedacht dat deze instructies kunnen wijzigen.`,
  ], naam_trainee);

  drawSection('Opleider', [
    `Dat ik er getuige van ben dat bovengenoemde kandidaat de interne opleiding met goed gevolg heeft doorlopen en mij daarbij ervan heeft overtuigd dat hij/zij over de kennis en vaardigheden beschikt die noodzakelijk zijn voor het uitoefenen van zijn/haar functie op de betreffende boot.`,
    `Hierbij verwijs ik naar het desbetreffende "formulier beoordeling trainee" waarin mijn beoordeling op de diverse te toetsen onderdelen is vastgelegd.`,
  ], naam_opleider);

  drawSection('Bestuurslid', [
    `Dat ik namens het Bestuur op basis van eerder genoemde verklaringen bovengenoemde kandidaat toestemming geef tot het uitoefenen van zijn/haar functie op de betreffende Fietsboot, zoals hierboven is aangegeven.`,
  ], 'Bernard van de Weert');

  // Footer
  const FOOTER_H = 22;
  rect(page, 0, 0, width, FOOTER_H, C.bg);
  hline(page, 0, FOOTER_H, width, C.border);
  const ftxt = `de Fietsboot  ·  Verklaring van Bekwaamheid  ·  Gegenereerd op ${vandaag}`;
  const fw = normal.widthOfTextAtSize(ftxt, 8);
  text(page, ftxt, (width - fw)/2, 8, normal, 8, C.text3);

  return doc.save();
}
